int parse_int32(const char *s, int32_t *out)
{
    if (s == NULL || out == NULL)
        return 0;

    /* skip leading whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s == '\0')
        return 0;

    /* optional sign */
    int sign = 1;
    if (*s == '+') {
        s++;
    } else if (*s == '-') {
        sign = -1;
        s++;
    }

    if (*s == '\0')
        return 0;

    /* parse digits */
    int32_t acc = 0;
    int32_t const hi = sign > 0 ? INT32_MAX : INT32_MIN;
    int32_t const lo = sign > 0 ? INT32_MAX / 10 : INT32_MIN / 10;
    int32_t const rem = sign > 0 ? INT32_MAX % 10 : -(INT32_MIN % 10);

    while (*s != '\0') {
        /* skip trailing whitespace (only allowed at end) */
        if (isspace((unsigned char)*s)) {
            /* allow trailing whitespace only if next char is also whitespace or end */
            const char *next = s + 1;
            while (isspace((unsigned char)*next))
                next++;
            if (*next != '\0')
                return 0; /* non-whitespace after whitespace => extra chars */
            break;
        }

        if (*s < '0' || *s > '9')
            return 0; /* non-digit character */

        int digit = *s - '0';

        /* overflow/underflow check before multiplying and adding */
        if (acc < lo || (acc == lo && digit > rem))
            return 0;

        acc = acc * 10 + digit;
        s++;
    }

    if (sign < 0)
        acc = -acc;

    *out = acc;
    return 1;
}

